// =========================
// OVERVIEW VIEW (Обозреватель)
// =========================

function OverviewView({ token }) {
  // Appear gate (Phase 4b): page-level so the overview cards stagger once on entry.
  const appearGate = useRef(new Set());
  const [overviewType, setOverviewType] = useState("express");
  const [overviews, setOverviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [generateError, setGenerateError] = useState(null);

  const apiUrl = process.env.REACT_APP_API_URL || "http://localhost:8000";
  const authHeaders = token ? { Authorization: `Bearer ${token}` } : {};

  const loadOverviews = () => {
    setLoading(true);
    fetch(`${apiUrl}/api/market/overviews?type=${overviewType}`)
      .then((r) => r.ok ? r.json() : [])
      .then((d) => { setOverviews(d); setLoading(false); })
      .catch(() => { setOverviews([]); setLoading(false); });
  };

  useEffect(() => { loadOverviews(); }, [overviewType]);

  const handleGenerate = () => {
    setGenerating(true);
    setGenerateError(null);
    fetch(`${apiUrl}/api/market/overviews/generate?type=${overviewType}`, { method: "POST", headers: authHeaders })
      .then((r) => r.json().then((d) => ({ ok: r.ok, data: d })))
      .then(({ ok, data }) => {
        if (ok) loadOverviews();
        else setGenerateError(data.detail || "Ошибка генерации обзора");
      })
      .catch((e) => setGenerateError(e.message || "Сетевая ошибка"))
      .finally(() => setGenerating(false));
  };

  const TABS = [
    { id: "express", label: "Экспресс", icon: Zap },
    { id: "detailed", label: "Детальный", icon: FileText },
    { id: "deep", label: "Глубокий", icon: BookOpen },
  ];

  const mockFallback = MOCK_MARKET_NEWS[overviewType] || [];
  // Depth level → Badge tone. These are content DEPTH categories, not severity,
  // so we keep them on neutral data-viz tones: warning(gold) is reserved for
  // risk callouts and success/danger for signed deltas — none apply here.
  const typeTone = {
    express: "info",
    detailed: "accent",
    deep: "neutral",
  };

  return (
    <div>
      <div className="view-header">
        <h1 className="view-title">Обозреватель рынка</h1>
        <p className="view-subtitle">Контекстное понимание рыночного фона</p>
      </div>

      <div className="tw-flex tw-flex-wrap tw-items-center tw-gap-2 tw-mb-6">
        {TABS.map((tab) => {
          const Icon = tab.icon;
          return (
            <Chip
              key={tab.id}
              selected={overviewType === tab.id}
              onClick={() => setOverviewType(tab.id)}
            >
              <Icon size={13} className="tw-shrink-0" aria-hidden="true" />
              {tab.label}
            </Chip>
          );
        })}

        <Button
          onClick={handleGenerate}
          disabled={generating}
          loading={generating}
          variant="secondary"
          iconLeft={!generating ? <Zap size={14} /> : null}
          className="tw-ml-auto"
        >
          {generating ? "Генерируем..." : "Сгенерировать обзор"}
        </Button>
      </div>

      {generateError && (
        <div
          role="alert"
          className="tw-mb-4 tw-rounded-md tw-border tw-border-danger tw-bg-danger-soft tw-px-4 tw-py-3 tw-text-[14px] tw-text-danger"
        >
          {generateError}
        </div>
      )}

      {loading ? (
        <div className="flex items-center justify-center py-16">
          <div className="tw-text-text-secondary tw-animate-pulse">Загружаем обзор...</div>
        </div>
      ) : overviews.length > 0 ? (
        <AppearGroup gate={appearGate.current} groupId="overview-cards" className="space-y-4">
          {overviews.map((item) => (
            <Card key={item.id}>
              <div className="tw-flex tw-items-center tw-justify-between tw-gap-2 tw-mb-3">
                <span className="tw-font-mono tw-text-[13px] tw-text-text-tertiary">{item.period}</span>
                <Badge tone={typeTone[item.overview_type] || "info"}>
                  {item.overview_type}
                </Badge>
              </div>
              <p className="tw-text-[14px] tw-leading-[22px] tw-text-text-secondary">{item.content}</p>
            </Card>
          ))}
        </AppearGroup>
      ) : (
        <div className="space-y-4">
          <p className="tw-text-[12px] tw-italic tw-text-text-tertiary tw-mb-2">
            Данных из API нет — показываем тестовые данные
          </p>
          <div className="tw-grid tw-gap-3" style={{ gridTemplateColumns: "repeat(auto-fit,minmax(300px,1fr))" }}>
            {mockFallback.map((news, i) => (
              <Card key={i}>
                <div className="tw-flex tw-gap-3 tw-items-start">
                  <Zap size={16} className="tw-text-accent tw-shrink-0 tw-mt-0.5" aria-hidden="true" />
                  <div>
                    {news.time && (
                      <div className="tw-font-mono tw-text-[11px] tw-text-text-tertiary tw-mb-1">
                        {news.time}
                      </div>
                    )}
                    <p className="tw-text-[13px] tw-leading-[20px] tw-text-text-secondary">
                      {news.text || news.title}
                    </p>
                    {news.desc && (
                      <p className="tw-text-[12px] tw-text-text-secondary tw-mt-1.5">{news.desc}</p>
                    )}
                  </div>
                </div>
              </Card>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

// =========================
// SIDEBAR
// =========================

const Sidebar = ({ activeTab, setActiveTab, theme, toggleTheme, user }) => {
  const cx = (...parts) => parts.filter(Boolean).join(" ");
  const reducedMotion = usePrefersReducedMotion();
  const NAV = [
    { id: "companies", icon: BarChart2, label: "Рынок" },
    { id: "overview",  icon: Globe,     label: "Обозреватель" },
    { id: "portfolio", icon: Briefcase, label: "Портфель" },
    { id: "pricing",   icon: CreditCard, label: "Тарифы" },
  ];

  // Active-indicator: a thin accent bar on the LEFT of the active nav icon.
  // Rendered as a child of the active IconButton (which becomes tw-relative)
  // and centred with top-1/2 / -translate-y-1/2, so its vertical centre always
  // sits EXACTLY on the icon centre — no DOM measurement / fixed-STEP math that
  // could drift (the earlier measured & STEP=44 approaches drifted DOWN because
  // the Tooltip wrapper is inline-flex and adds a sub-pixel strut per row).

  return (
    <aside className="sidebar">
      <Tooltip label="На главную" side="right">
        <button
          type="button"
          aria-label="Basis — на главную"
          onClick={() => setActiveTab("landing")}
          /* appearance-none + bg-transparent + border-0 + p-0: preflight is OFF,
             so a raw <button> would otherwise show the browser's native chrome
             (grey/beige ButtonFace square + border) behind the mark. Strip it →
             clean cobalt B straight on the sidebar background. */
          className="tw-appearance-none tw-bg-transparent tw-border-0 tw-p-0 tw-cursor-pointer tw-mb-3 tw-flex tw-h-9 tw-w-9 tw-items-center tw-justify-center tw-rounded-md tw-transition-colors hover:tw-bg-accent-soft focus-visible:tw-outline-none focus-visible:tw-ring-2 focus-visible:tw-ring-accent"
        >
          <BasisLogomark size={30} slit="var(--bg-base)" crisp />
        </button>
      </Tooltip>

      <div className="sidebar-divider" />

      <div className="tw-flex tw-flex-col tw-gap-1">
        {NAV.map(({ id, icon: Icon, label }) => {
          const active = activeTab === id;
          return (
            <Tooltip key={id} label={label} side="right">
              <IconButton
                aria-label={label}
                onClick={() => setActiveTab(id)}
                className={active ? "tw-relative tw-bg-accent-soft" : ""}
                style={{ color: active ? "var(--accent)" : "var(--sidebar-icon-idle)" }}
              >
                {active && (
                  <span
                    aria-hidden="true"
                    /* Centred via INLINE top/transform (not tw-top-1/2 / -tw-translate-y-1/2):
                       preflight is OFF, so Tailwind never declares the default
                       --tw-translate-x:0, which makes the class-based transform
                       invalid → the bar dropped ~12px. Inline transform is immune. */
                    className="tw-absolute tw-left-[-12px] tw-w-[3px] tw-h-6 tw-rounded-r-sm tw-bg-accent"
                    style={{ top: "50%", transform: "translateY(-50%)", transition: reducedMotion ? "none" : "opacity var(--motion-base) var(--ease-out)" }}
                  />
                )}
                <Icon size={20} />
              </IconButton>
            </Tooltip>
          );
        })}
      </div>

      <div className="sidebar-spacer" />

      <Tooltip label={theme === "dark" ? "Светлая тема" : "Тёмная тема"} side="right">
        <IconButton
          aria-label={theme === "dark" ? "Светлая тема" : "Тёмная тема"}
          onClick={toggleTheme}
          style={{ color: "var(--sidebar-icon-idle)" }}
        >
          {theme === "dark" ? <Sun size={18} /> : <Moon size={18} />}
        </IconButton>
      </Tooltip>

      <Tooltip label={user ? "Профиль" : "Войти"} side="right">
        <IconButton
          aria-label={user ? "Профиль" : "Войти"}
          onClick={() => setActiveTab("profile")}
          className={cx("tw-mb-1", activeTab === "profile" && "tw-bg-accent-soft")}
          style={{ color: activeTab === "profile" ? "var(--accent)" : "var(--sidebar-icon-idle)" }}
        >
          {user ? (
            <span className="tw-inline-flex tw-items-center tw-justify-center tw-w-7 tw-h-7 tw-rounded-pill tw-bg-accent tw-text-on-accent tw-text-[12px] tw-font-bold tw-leading-none">
              {user.email.slice(0, 2).toUpperCase()}
            </span>
          ) : (
            <User size={20} />
          )}
        </IconButton>
      </Tooltip>
    </aside>
  );
};

// =========================
// APP
// =========================

export default function App() {
  const apiUrl = process.env.REACT_APP_API_URL || "http://localhost:8000";

  const [activeTab, setActiveTab] = useState("landing");
  const [selectedCompany, setSelectedCompany] = useState(null);
  const [theme, setTheme] = useState(() => {
    const stored = localStorage.getItem("basis_theme");
    if (stored === "dark" || stored === "light") return stored;
    // No explicit choice → default LIGHT (per design constitution; mirrors anti-FOUC script).
    return "light";
  });

  const [user, setUser] = useState(() => {
    try { return JSON.parse(localStorage.getItem("basis_user")); } catch { return null; }
  });
  const [token, setToken] = useState(() => localStorage.getItem("basis_token") || null);
  const [showAuthModal, setShowAuthModal] = useState(false);

  useEffect(() => {
    const el = document.documentElement;
    el.classList.toggle("dark", theme === "dark");
    // Keep data-theme in sync for backward-compatible selectors.
    el.setAttribute("data-theme", theme);
    localStorage.setItem("basis_theme", theme);
  }, [theme]);

  useEffect(() => {
    if (!token) return;
    fetch(`${apiUrl}/api/auth/me`, { headers: { Authorization: `Bearer ${token}` } })
      .then(r => r.ok ? r.json() : null)
      .then(u => {
        if (u) { setUser(u); localStorage.setItem("basis_user", JSON.stringify(u)); }
        else handleLogout();
      })
      .catch(() => {});
  }, []);

  const handleLogin = (newUser, newToken) => {
    setUser(newUser);
    setToken(newToken);
    setShowAuthModal(false);
  };

  const handleLogout = () => {
    localStorage.removeItem("basis_token");
    localStorage.removeItem("basis_user");
    setUser(null);
    setToken(null);
    setActiveTab("landing");
  };

  const navigate = (tab) => {
    setActiveTab(tab);
    setSelectedCompany(null);
  };

  const renderView = () => {
    if (selectedCompany) {
      return <CompanyCard company={selectedCompany} onBack={() => setSelectedCompany(null)} />;
    }
    switch (activeTab) {
      case "landing":
        return <LandingView onNavigate={navigate} onShowAuth={() => setShowAuthModal(true)} user={user} />;
      case "companies":
        return <CompaniesView onSelectCompany={setSelectedCompany} />;
      case "overview":
        return <OverviewView token={token} />;
      case "portfolio":
        return <PortfolioView token={token} onAuthRequired={() => setShowAuthModal(true)} onOpenCompany={setSelectedCompany} />;
      case "pricing":
        return <PricingView user={user} onShowAuth={() => setShowAuthModal(true)} />;
      case "profile":
        return (
          <ProfileView
            user={user}
            token={token}
            onLogout={handleLogout}
            onNavigate={navigate}
            onShowAuth={() => setShowAuthModal(true)}
          />
        );
      default:
        return <LandingView onNavigate={navigate} onShowAuth={() => setShowAuthModal(true)} user={user} />;
    }
  };

  if (typeof window !== "undefined" && window.location.pathname === "/_design") {
    return <DesignSystem />;
  }

  return (
    <div data-theme={theme} className="app-layout tw-bg-bg-base tw-text-text-primary">
      <Sidebar
        activeTab={selectedCompany ? null : activeTab}
        setActiveTab={navigate}
        theme={theme}
        toggleTheme={() => setTheme(t => t === "dark" ? "light" : "dark")}
        user={user}
      />

      <main className="app-main">
        {renderView()}
      </main>

      {showAuthModal && (
        <AuthModal onClose={() => setShowAuthModal(false)} onSuccess={handleLogin} />
      )}
    </div>
  );
}
